const { Manifold, CrossSection, Curves } = api;

// Declare parameters for the customizable chain
const p = api.params({
  wireDiameter: { type: 'number', default: 3, min: 1, max: 10, step: 0.1, unit: 'mm', label: 'Wire Diameter' },
  innerLength: { type: 'number', default: 14, min: 5, max: 50, step: 0.5, unit: 'mm', label: 'Link Inner Length' },
  innerWidth: { type: 'number', default: 8, min: 2, max: 30, step: 0.5, unit: 'mm', label: 'Link Inner Width' },
  clearance: { type: 'number', default: 0.5, min: 0.1, max: 2, step: 0.1, unit: 'mm', label: 'Interlocking Clearance' },
});

const wireDiameter = p.wireDiameter;
const innerWidth = p.innerWidth;
// Clamp innerLength so it is always at least innerWidth to maintain physical structure
const innerLength = Math.max(innerWidth + 1, p.innerLength);
const clearance = p.clearance;

const rInner = innerWidth / 2;
const rCenter = rInner + wireDiameter / 2;
const lStraight = Math.max(0, innerLength - innerWidth);

// Create single link centerline path
const pathPoints = [];
const segments = 32; // Resolution for manual path sampling (180 deg caps)

// Positive Y-end arc (0 to 180 degrees)
for (let i = 0; i <= segments; i++) {
  const theta = (i / segments) * Math.PI;
  const x = rCenter * Math.cos(theta);
  const y = lStraight / 2 + rCenter * Math.sin(theta);
  pathPoints.push([x, y, 0]);
}

// Negative Y-end arc (180 to 360 degrees)
for (let i = 0; i <= segments; i++) {
  const theta = Math.PI + (i / segments) * Math.PI;
  const x = rCenter * Math.cos(theta);
  const y = -lStraight / 2 + rCenter * Math.sin(theta);
  pathPoints.push([x, y, 0]);
}

// Close the loop by returning to the start point
pathPoints.push(pathPoints[0]);

// Sweep the profile along the path
// Omit segments on the circle constructor so it inherits the user's quality preset
const profile = CrossSection.circle(wireDiameter / 2);
const singleLink = Curves.sweep(profile, pathPoints);

// Calculate exact interlocking pitch
// P = L_straight + 2 * R_inner - clearance
const pitch = lStraight + 2 * rInner - clearance;

// Assemble 5 interlocking links
const chain = [];
for (let i = 0; i < 5; i++) {
  let link = singleLink.clone();

  // Rotate even links 90 degrees around Y-axis to interlock
  if (i % 2 === 1) {
    link = link.rotate([0, 90, 0]);
  }

  // Translate along the chain axis (Y)
  link = link.translate([0, i * pitch, 0]);

  // Apply distinct gold/silver alternating colors and labels
  const labelName = `link_${i + 1}`;
  const color = (i % 2 === 0) ? '#cca43b' : '#b0b7bd'; // Gold & Silver
  link = api.label(link, labelName, { color });

  chain.push(link);
}

// Union and perform component check
return api.expectUnion(chain, { expectComponents: 5 });

const { Manifold, CrossSection, Curves } = api;

// Declare parameters for the customizable spiral chain
const p = api.params({
  numLinks: { type: 'int', default: 30, min: 5, max: 100, label: 'Number of Links' },
  linkScale: { type: 'number', default: 1.0, min: 0.3, max: 3.0, step: 0.1, label: 'Overall Link Scale' },
  wireDiameter: { type: 'number', default: 3, min: 1, max: 10, step: 0.1, unit: 'mm', label: 'Wire Diameter (Base)' },
  innerLength: { type: 'number', default: 14, min: 5, max: 50, step: 0.5, unit: 'mm', label: 'Link Inner Length (Base)' },
  innerWidth: { type: 'number', default: 8, min: 2, max: 30, step: 0.5, unit: 'mm', label: 'Link Inner Width (Base)' },
  clearance: { type: 'number', default: 0.5, min: 0.1, max: 2, step: 0.1, unit: 'mm', label: 'Clearance' },
});

// Scale all dimensions proportionally based on linkScale
const s = p.linkScale;
const numLinks = p.numLinks;
const wireDiameter = p.wireDiameter * s;
const innerWidth = p.innerWidth * s;
// Ensure length is at least width + 1 before scaling to prevent structural collapse
const baseLength = Math.max(p.innerWidth + 1, p.innerLength);
const innerLength = baseLength * s;
const clearance = p.clearance * s;

const rInner = innerWidth / 2;
const rCenter = rInner + wireDiameter / 2;
const lStraight = Math.max(0, innerLength - innerWidth);

// 1. Create a single horizontal base link centered at the origin, oriented along the Y-axis
const pathPoints = [];
const segments = 32;

for (let i = 0; i <= segments; i++) {
  const theta = (i / segments) * Math.PI;
  const x = rCenter * Math.cos(theta);
  const y = lStraight / 2 + rCenter * Math.sin(theta);
  pathPoints.push([x, y, 0]);
}
for (let i = 0; i <= segments; i++) {
  const theta = Math.PI + (i / segments) * Math.PI;
  const x = rCenter * Math.cos(theta);
  const y = -lStraight / 2 + rCenter * Math.sin(theta);
  pathPoints.push([x, y, 0]);
}
pathPoints.push(pathPoints[0]);

const profile = CrossSection.circle(wireDiameter / 2);
const baseLink = Curves.sweep(profile, pathPoints);

// Calculate the interlocking pitch
const pitch = lStraight + 2 * rInner - clearance;

// 2. Setup the Archimedean Spiral parameters
// The spacing between adjacent spiral rings must clear the outer width of the tilted link
const outerWidth = innerWidth + 2 * wireDiameter;
const ringSpacing = outerWidth * 1.6; // Safety margin to prevent ring-to-ring fusing
const a = ringSpacing / (2 * Math.PI);

// Start theta further out to avoid high curvature at the center
let theta = 4.0 * Math.PI;

const chain = [];

// 3. Place and orient each link sequentially along the spiral path
for (let i = 0; i < numLinks; i++) {
  const r = a * theta;
  const x = r * Math.cos(theta);
  const y = r * Math.sin(theta);

  // Calculate tangent direction vector at this theta
  const dx = a * Math.cos(theta) - r * Math.sin(theta);
  const dy = a * Math.sin(theta) + r * Math.cos(theta);
  const angleRad = Math.atan2(dy, dx);
  const angleDeg = (angleRad * 180) / Math.PI;

  // Clone the base link
  let link = baseLink.clone();

  // A. Apply longitudinal rotation (tilted 45 degrees so all links can sit flat on the bed)
  const rollAngle = (i % 2 === 0) ? 45 : -45;
  link = link.rotate([0, rollAngle, 0]);

  // B. Drop the rotated link exactly onto the build plate (Z = 0)
  const bbox = api.bbox(link);
  link = link.translate([0, 0, -bbox.min[2]]);

  // C. Rotate around Z to align its long axis (Y) with the spiral tangent vector
  link = link.rotate([0, 0, angleDeg - 90]);

  // D. Move to its calculated spiral coordinate
  link = link.translate([x, y, 0]);

  // Apply distinct alternating colors (Gold & Silver) and labels
  const labelName = `link_${i + 1}`;
  const color = (i % 2 === 0) ? '#cca43b' : '#b0b7bd';
  link = api.label(link, labelName, { color });

  chain.push(link);

  // Step theta forward for the next link of pitch P
  const ds_dtheta = Math.sqrt(r * r + a * a);
  const dTheta = pitch / ds_dtheta;
  theta += dTheta;
}

// Union the entire spiral chain of components
return api.expectUnion(chain, { expectComponents: numLinks });
